function summarizeResults(results) {
  const summary = {
    total: results.length,
    detected: 0,
    partial: 0,
    failed: 0,
    check_supported: 0,
    check_rules_detected: 0,
  };

  for (const result of results) {
    if (result.detected) {
      summary.detected += 1;
    }
    if (result.status === 'partial') {
      summary.partial += 1;
    } else if (result.status === 'fail') {
